import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import './NewTicket.css';

function NewTicket() {
    const [description, setDescription] = useState('');
    const [file, setFile] = useState(null);
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const handleFileChange = (e) => {
        setFile(e.target.files[0]);
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);

        const formData = new FormData();
        formData.append('description', description);
        if (file) {
            formData.append('file', file);
        }

        try {
            const baseUrl = process.env.REACT_APP_API_BASE_URL || '/api';
            const cleanBaseUrl = baseUrl.endsWith('/') ? baseUrl.slice(0, -1) : baseUrl;

            const res = await fetch(`${cleanBaseUrl}/tickets/create`, {
                method: 'POST',
                body: formData,
            });

            if (res.ok) {
                alert('Ticket successfully uploaded and added to database!');
                navigate('/my-tickets'); // Redirect to My Tickets to see the submission
            } else {
                const error = await res.json();
                alert(error.message || 'Failed to submit ticket');
            }
        } catch (err) {
            console.error(err);
            alert('Network error. Please ensure the backend is running.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="ticket-container">
            <div className="ticket-card">
                <h2>Raise a Ticket</h2>
                <p>Our AI will automatically categorize and route your issue.</p>

                <form onSubmit={handleSubmit} className="ticket-form">
                    <div className="form-group">
                        <textarea
                            placeholder="Describe your issue in detail..."
                            value={description}
                            onChange={(e) => setDescription(e.target.value)}
                            required
                        />
                    </div>

                    <div className="file-upload-group" onClick={() => document.getElementById('ticketFile').click()}>
                        <input
                            type="file"
                            id="ticketFile"
                            accept=".txt"
                            onChange={handleFileChange}
                        />
                        <div className="file-label">
                            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4M17 8l-5-5-5 5M12 3v12" />
                            </svg>
                            <span>{file ? 'Change Text File' : 'Upload Log or Text File'}</span>
                            {file && <div className="selected-file">{file.name}</div>}
                        </div>
                    </div>

                    <button type="submit" className="submit-btn" disabled={loading}>
                        {loading ? 'Submitting...' : 'Submit Ticket'}
                    </button>
                </form>

                <Link to="/" className="back-link">← Back to Dashboard</Link>
            </div>
        </div>
    );
}

export default NewTicket;
